#include <stdio.h>
#include <unistd.h>
#include <stdlib.h>
#include <string.h>

int main() {
 int pipefd[2];
 pid_t pid;
 char buffer[100];

 // Create pipe
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 exit(1);
 }

 // Fork child process
 pid = fork();

 if (pid < 0) {
 perror("fork failed");
 exit(1);
 }

 if (pid == 0) {
 // Child process - write to pipe
 close(pipefd[0]); // Close read end
 char msg[] = "Hello from child!";
 write(pipefd[1], msg, strlen(msg));
 close(pipefd[1]);
 exit(0);
 } else {
 // Parent process - read from pipe
 close(pipefd[1]); // Close write end
 read(pipefd[0], buffer, sizeof(buffer));
 printf("Parent received: %s\n", buffer);
 close(pipefd[0]);
 wait(NULL);
 }
 return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <stdlib.h>

int main() {
 int pipefd[2];
 pid_t pid1, pid2;

 // Create pipe
 if (pipe(pipefd) == -1) {
 perror("pipe failed");
 exit(1);
 }

 // First child - executes 'ls'
 pid1 = fork();
 if (pid1 == 0) {
 // Redirect stdout to pipe write end
 dup2(pipefd[1], STDOUT_FILENO);
 close(pipefd[0]);
 close(pipefd[1]);

 // Execute 'ls'
 execlp("ls", "ls", (char *)NULL);
 perror("execlp ls failed");
 exit(1);
 }

 // Second child - executes 'wc -l'
 pid2 = fork();
 if (pid2 == 0) {
 // Redirect stdin to pipe read end
 dup2(pipefd[0], STDIN_FILENO);
 close(pipefd[1]);
 close(pipefd[0]);

 // Execute 'wc -l'
 execlp("wc", "wc", "-l", (char *)NULL);
 perror("execlp wc failed");
 exit(1);
 }

 // Parent closes both pipe ends
 close(pipefd[0]);
 close(pipefd[1]);

 // Wait for both children
 waitpid(pid1, NULL, 0);
 waitpid(pid2, NULL, 0);

 return 0;
}

