#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/stat.h>

int main() {
 const char *fifo_path = "/tmp/myfifo";

 // Create FIFO if not exists
 mkfifo(fifo_path, 0666);

 // Open for writing
 int fd = open(fifo_path, O_WRONLY);
 if (fd == -1) {
 perror("open failed");
 return 1;
 }

 // Write data
 char msg[] = "Data from writer";
 write(fd, msg, sizeof(msg));

 close(fd);
 return 0;
}

