#include <stdio.h>
#include <unistd.h>
#include <stdlib.h>
#include <string.h>

int main() {
 int pipe_parent_to_child[2];
 int pipe_child_to_parent[2];
 pid_t pid;

 // Create two pipes for bidirectional communication
 pipe(pipe_parent_to_child);
 pipe(pipe_child_to_parent);

 pid = fork();

 if (pid == 0) {
 // Child process
 char msg[100];

 // Close unused ends in child
 close(pipe_parent_to_child[1]); // Write end of parent->child
 close(pipe_child_to_parent[0]); // Read end of child->parent

 // Read from parent
 read(pipe_parent_to_child[0], msg, sizeof(msg));
 printf("Child received: %s\n", msg);

 // Send response to parent
 char response[] = "Hello from child!";
 write(pipe_child_to_parent[1], response, strlen(response));

 // Close remaining ends
 close(pipe_parent_to_child[0]);
 close(pipe_child_to_parent[1]);

 exit(0);
 } else {
 // Parent process
 char buffer[100];

 // Close unused ends in parent
 close(pipe_parent_to_child[0]); // Read end of parent->child
 close(pipe_child_to_parent[1]); // Write end of child->parent

 // Send message to child
 char msg[] = "Hello from parent!";
 write(pipe_parent_to_child[1], msg, strlen(msg));

 // Read response from child
 read(pipe_child_to_parent[0], buffer, sizeof(buffer));
 printf("Parent received: %s\n", buffer);

 // Close remaining ends
 close(pipe_parent_to_child[1]);
 close(pipe_child_to_parent[0]);

 wait(NULL);
 }

 return 0;
}
